// ============================================================
// IIV v2.0 — HEDONIC PRICING MODEL
// Base: Median pre-GPF UK auction result (47 comps, 2022-2026)
// Adjustments: Multiplicative hedonic premiums per attribute
// Confidence interval: ±8% (high), ±12% (medium), ±18% (low)
// ============================================================
export const IIV_BASE = {
  preGPFMedian: 235000,    // Median pre-GPF UK auction/dealer result
  postGPFMedian: 210000,   // Median post-GPF UK result
  
  // Multiplicative premiums (applied sequentially to base)
  premiums: {
    atelier: 0.13,           // +13% for Atelier commission
    specialColour: 0.08,     // +8% for special/historic colour
    desirableColour: 0.04,   // +4% for desirable (non-standard) colour
    fullCarbon: 0.07,        // +7% for full carbon pack
    partialCarbon: 0.03,     // +3% for partial carbon
    daytonaSeats: 0.04,      // +4% for Daytona/racing seats
    desirableInterior: 0.04, // +4% for desirable contrast interior
    singleOwner: 0.06,       // +6% for single owner
    fullServiceHistory: 0.04,// +4% for full Ferrari dealer service history
    carbonCeramicBrakes: 0.04, // +4% for CCB
    telemetryKit: 0.02,      // +2% for telemetry/track pack
    climateStorage: 0.02,    // +2% for documented climate storage
    
    // Penalties
    accidentHistory: -0.20,  // -20% for any accident history
    highMileage: -0.003,     // -0.3% per 1,000 miles above 15k
    veryHighMileage: -0.005, // -0.5% per 1,000 miles above 25k (compounding)
    noServiceHistory: -0.06, // -6% for unknown/incomplete service history
    multipleOwners: -0.04,   // -4% for 3+ owners
  },
  
  // Confidence interval multipliers
  confidenceIntervals: {
    high: 0.08,    // ±8% — full spec data, confirmed history
    medium: 0.12,  // ±12% — partial spec data or unconfirmed history
    low: 0.18,     // ±18% — limited data, unconfirmed key attributes
  }
};

// ============================================================
// ANALYST FORECAST PARAMETERS
// Sources: Hagerty (2026 Market Report), Full Throttle Talk,
//          The Classic Valuer, Octoclassic, Romans International
// ============================================================
const BASE_RATE = 0.04;        // 4% pa base appreciation
const OPTIMISTIC_RATE = 0.07;  // 7% pa optimistic
const PESSIMISTIC_RATE = 0.01; // 1% pa pessimistic

function calcPrediction(
  askingPrice: number,
  scoreMultiplier: number,
  years: number,
  rate: number
): number {
  return Math.round(askingPrice * scoreMultiplier * Math.pow(1 + rate, years) / 1000) * 1000;
}

